@Override
protected StringCollectionDeserializer<Collection<String>> modifyCopyForSplitOrMerge(final Object original, 
        boolean splitAtRoot, final String attrName,
        String[] elementNamesToAdd) {
    final StringCollectionDeserializer<Collection<String>> copy = super.modifyCopyForSplitOrMerge(original, 
            splitAtRoot, attrName, elementNamesToAdd);

    return new StringCollectionDeserializer<Collection<String>>(){

        @Override
        protected Collection<String> instantiate(Class<Collection<String>> type) throws IOException {

            try {
                Constructor<Collection<String>> con = type.getConstructor(ImmutableSet.class);

                return con.newInstance(ImmutableSet.of());

            } catch (NoSuchMethodException | SecurityException e){
                    throw new IOException("Unable to instantiate ImmutableSet",e);
            } catch (InstantiationException | IllegalAccessException | IllegalArgumentException | InvocationTargetException e) {
                throw new IOException ("Unexpected exception thrown while trying to instantiate ImmutableSet.", e);
            }
        }

    };
}

